import asyncio
from typing import Awaitable

class AsyncHitLGate:
    def __init__(self,
                 primary_review: Callable[[HitLRequest], Awaitable[HitLDecision]],
                 escalation_review: Callable[[HitLRequest], Awaitable[HitLDecision]],
                 primary_timeout: float = 120.0,
                 escalation_timeout: float = 300.0):
        self._primary = primary_review
        self._escalation = escalation_review
        self._primary_timeout = primary_timeout
        self._escalation_timeout = escalation_timeout

    async def request_approval(self, req: HitLRequest) -> HitLDecision:
        # Try primary reviewer first
        try:
            return await asyncio.wait_for(
                self._primary(req), timeout=self._primary_timeout
            )
        except asyncio.TimeoutError:
            pass  # escalate

        # Escalate to backup
        try:
            return await asyncio.wait_for(
                self._escalation(req), timeout=self._escalation_timeout
            )
        except asyncio.TimeoutError:
            return HitLDecision(
                approved=False,
                reviewer="timeout-escalation",
                note="Both reviewers timed out — auto-declined for safety",
            )

from collections import defaultdict

class OversightMetrics:
    """Track HitL decision patterns to calibrate oversight policy."""
    def __init__(self):
        self._decisions: dict[str, list[bool]] = defaultdict(list)

    def record(self, tool_name: str, approved: bool) -> None:
        self._decisions[tool_name].append(approved)

    def approval_rates(self) -> dict[str, float]:
        return {
            tool: sum(decisions) / len(decisions)
            for tool, decisions in self._decisions.items()
            if decisions
        }

    def oversight_candidates(self, low_threshold: float = 0.70,
                              high_threshold: float = 0.95) -> dict:
        """
        Returns tools that may need policy changes:
        - below low_threshold: agent is frequently wrong → increase oversight
        - above high_threshold: agent is reliable → consider removing requirement
        """
        rates = self.approval_rates()
        return {
            "increase_oversight": [t for t, r in rates.items() if r < low_threshold],
            "reduce_oversight":   [t for t, r in rates.items() if r > high_threshold],
        }

