from dataclasses import dataclass, field

@dataclass
class PipelineOversightEvent:
    """Emitted at key points in a multi-agent pipeline for human review."""
    event_type: str    # "plan", "handoff", "irreversible_action", "completion"
    from_agent: str
    to_agent: str | None
    data_summary: str
    requires_review: bool = False
    tags: list[str] = field(default_factory=list)

class PipelineOversightLog:
    def __init__(self):
        self._events: list[PipelineOversightEvent] = []

    def emit(self, event: PipelineOversightEvent) -> None:
        self._events.append(event)
        if event.requires_review:
            self._notify_human(event)

    def _notify_human(self, event: PipelineOversightEvent) -> None:
        # In production: send to oversight dashboard, Slack, or email
        print(f"[OVERSIGHT] {event.event_type} from {event.from_agent}: {event.data_summary[:200]}")

    def review_summary(self) -> dict:
        return {
            "total_events": len(self._events),
            "requiring_review": sum(1 for e in self._events if e.requires_review),
            "by_type": {
                et: sum(1 for e in self._events if e.event_type == et)
                for et in {"plan","handoff","irreversible_action","completion"}
            },
        }

# Usage in an orchestrator
oversight_log = PipelineOversightLog()

def orchestrate_with_oversight(task: str, agents: list) -> str:
    oversight_log.emit(PipelineOversightEvent(
        event_type="plan",
        from_agent="orchestrator",
        to_agent=None,
        data_summary=f"Starting pipeline for: {task[:100]}",
    ))

    result = None
    for i, agent in enumerate(agents):
        result = agent(result or task)
        next_agent = agents[i+1].__name__ if i+1 < len(agents) else None
        oversight_log.emit(PipelineOversightEvent(
            event_type="handoff",
            from_agent=agent.__name__,
            to_agent=next_agent,
            data_summary=str(result)[:200],
            requires_review=(next_agent is None),  # review final output
        ))

    return result
